<?php $this->extend('layouts.public'); ?><?php $this->section('content'); ?><section class="section"><div class="container"><h1>Trailer listings</h1><?php $this->include('partials.provider-nav',['active'=>'trailer-listings']); ?><a class="btn btn-primary" href="<?= e(url('provider/trailer-listings/form')) ?>">Add trailer</a><?php if (empty($listings)): ?><div class="card"><p>No trailer listings yet.</p></div><?php else: ?><div class="table-wrap"><table class="data"><thead><tr><th>Title</th><th>Type</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($listings as $listing): ?><tr><td><?= $this->e($listing['title']) ?></td><td><?= $this->e($listing['trailer_type']) ?></td><td><?= $this->e($listing['status']) ?></td><td><a href="<?= e(url('provider/trailer-listings/form?id='.(int)$listing['id'])) ?>">Edit</a></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></div></section><?php $this->endSection(); ?>
